@startuml
skinparam classAttributeIconSize 0

class KindleNotesHtml_1_23 {
    selector
}

class Selector <<enumeration>>{
    TITLE
    AUTHOR
    SECTIONS
    S_HEADING
    S_NOTE_HEADING
    S_NOTE_TEXT
}


abstract class "«KindleNotes»" KindleNotes as KN {
   title : String 
   author : String  
   notes: «List» NoteElement


parse()    
 } 

note right of KN::notes
<font color=red>has n</font><b></b> <i>notes </i>
end note



interface "«NoteElement»" NE {
section
heading
text

} 


KN o-- NE  

NE --|> MarkdownFormatter  


package ""<<kindlenotes>>"" #DDF4FF [[https://github.com/robertmartin8/kindles-notes]]# {


     abstract class "«KindleNotesCsv»" KNCsv {
        _csv

       -extract_notes ()     
      } 



         class "«KindleNotesText»" KNText {
            _text

           extract_notes ()         
          } 


             class "«KindleNotesMarkdown»" KNMD {
                convert(notes)            
              } 


